// ── CURSOR ────────────────────────────────────────────────────────────────────
function CustomCursor() {
  const dotRef  = useRef(null);
  const ringRef = useRef(null);
  const pos  = useRef({ x: 0, y: 0 });
  const ring = useRef({ x: 0, y: 0 });
  const [isTouch, setIsTouch] = useState(false);

  useEffect(() => { setIsTouch("ontouchstart" in window || navigator.maxTouchPoints > 0); }, []);

  useEffect(() => {
    if (isTouch) return;
    const move = (e) => {
      pos.current = { x: e.clientX, y: e.clientY };
      if (dotRef.current) { dotRef.current.style.left = e.clientX - 4 + "px"; dotRef.current.style.top = e.clientY - 4 + "px"; }
    };
    const onEnter = (e) => {
      if (e.target.closest("a, button")) {
        if (ringRef.current) { ringRef.current.style.width = "52px"; ringRef.current.style.height = "52px"; ringRef.current.style.borderColor = CRIMSON; }
        if (dotRef.current) dotRef.current.style.transform = "scale(2)";
      }
    };
    const onLeave = (e) => {
      if (e.target.closest("a, button")) {
        if (ringRef.current) { ringRef.current.style.width = "36px"; ringRef.current.style.height = "36px"; ringRef.current.style.borderColor = "rgba(199,37,26,0.5)"; }
        if (dotRef.current) dotRef.current.style.transform = "scale(1)";
      }
    };
    window.addEventListener("mousemove", move);
    window.addEventListener("mouseover", onEnter);
    window.addEventListener("mouseout", onLeave);
    let raf;
    const animate = () => {
      ring.current.x += (pos.current.x - ring.current.x) * 0.12;
      ring.current.y += (pos.current.y - ring.current.y) * 0.12;
      if (ringRef.current) { ringRef.current.style.left = ring.current.x - 18 + "px"; ringRef.current.style.top = ring.current.y - 18 + "px"; }
      raf = requestAnimationFrame(animate);
    };
    raf = requestAnimationFrame(animate);
    return () => { window.removeEventListener("mousemove", move); window.removeEventListener("mouseover", onEnter); window.removeEventListener("mouseout", onLeave); cancelAnimationFrame(raf); };
  }, [isTouch]);

  return isTouch ? null : (
    <>
      <div ref={dotRef}  className="cursor-dot"  style={{ pointerEvents: "none" }} />
      <div ref={ringRef} className="cursor-ring" style={{ pointerEvents: "none" }} />
    </>
  );
}

// ── SCROLL REVEAL ─────────────────────────────────────────────────────────────
function useScrollReveal() {
  useEffect(() => {
    const els = document.querySelectorAll(".fade-in");
    const obs = new IntersectionObserver(
      (entries) => entries.forEach((e) => { if (e.isIntersecting) e.target.classList.add("visible"); }),
      { threshold: 0.1 }
    );
    els.forEach((el) => obs.observe(el));
    return () => obs.disconnect();
  }, []);
}

// ── COUNTER ───────────────────────────────────────────────────────────────────
function Counter({ target, suffix = "" }) {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  const started = useRef(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !started.current) {
        started.current = true;
        if (isNaN(parseInt(target))) { setCount(target); return; }
        const end = parseInt(target);
        const step = Math.ceil(end / (1200 / 16));
        let cur = 0;
        const t = setInterval(() => { cur = Math.min(cur + step, end); setCount(cur); if (cur >= end) clearInterval(t); }, 16);
      }
    }, { threshold: 0.5 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [target]);
  return <span ref={ref}>{count}{suffix}</span>;
}

