  const line2 = "EU CUIDO DAS VENDAS.";

  useEffect(() => {
    let i = 0;
    const total = line1.length + line2.length;
    const t = setInterval(() => {
      setTyped(i <= line1.length ? line1.slice(0, i) : line1 + "\n" + line2.slice(0, i - line1.length));
      i++;
      if (i > total) clearInterval(t);
    }, 60);
    return () => clearInterval(t);
  }, []);

  const lines = typed.split("\n");

