// ── LIGHTBOX ──────────────────────────────────────────────────────────────────
function Lightbox({ item, onClose }) {
  const [zoom, setZoom] = useState(1);
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const [dragging, setDragging] = useState(false);
  const [start, setStart] = useState({ x: 0, y: 0 });
  const [lastPos, setLastPos] = useState({ x: 0, y: 0 });
  const [slide, setSlide] = useState(0);
  const lastDist = useRef(null);

  const imgs = item.imgs || (item.img ? [item.img] : []);
  const cur = imgs[slide];
  const hasPrev = slide > 0;
  const hasNext = slide < imgs.length - 1;
  const resetZoom = () => { setZoom(1); setPos({ x:0,y:0 }); setLastPos({ x:0,y:0 }); };
  const goPrev = () => { if (hasPrev) { setSlide(s=>s-1); resetZoom(); } };
  const goNext = () => { if (hasNext) { setSlide(s=>s+1); resetZoom(); } };

  useEffect(() => {
    const h = (e) => { if (e.key==="Escape") onClose(); if (e.key==="ArrowLeft") goPrev(); if (e.key==="ArrowRight") goNext(); };
    window.addEventListener("keydown", h);
    document.body.style.overflow = "hidden";
    return () => { window.removeEventListener("keydown", h); document.body.style.overflow = ""; };
  }, [slide]);

  const onWheel = (e) => { e.preventDefault(); setZoom(z=>Math.min(5,Math.max(1,z-e.deltaY*0.002))); };
  const onMouseDown = (e) => { if (zoom>1) { setDragging(true); setStart({ x:e.clientX-pos.x, y:e.clientY-pos.y }); } };
  const onMouseMove = (e) => { if (dragging&&zoom>1) setPos({ x:e.clientX-start.x, y:e.clientY-start.y }); };
  const onMouseUp = () => setDragging(false);
  const onTouchStart = (e) => { if (e.touches.length===1) setStart({ x:e.touches[0].clientX, y:e.touches[0].clientY }); };
  const onTouchMove = (e) => {
    if (e.touches.length===2) {
      const dx=e.touches[0].clientX-e.touches[1].clientX, dy=e.touches[0].clientY-e.touches[1].clientY;
      const dist=Math.sqrt(dx*dx+dy*dy);
      if (lastDist.current) setZoom(z=>Math.min(5,Math.max(1,z+(dist-lastDist.current)*0.01)));
      lastDist.current=dist;
    } else if (e.touches.length===1&&zoom>1) {
      setPos({ x:lastPos.x+e.touches[0].clientX-start.x, y:lastPos.y+e.touches[0].clientY-start.y });
    }
  };
  const onTouchEnd = () => { lastDist.current=null; setLastPos(pos); };
  const src = cur && cur.startsWith("http") ? cur : `data:image/png;base64,${cur}`;

  return (
    <div onClick={zoom===1?onClose:undefined} style={{ position:"fixed",inset:0,zIndex:9998,background:"rgba(0,0,0,0.96)",display:"flex",flexDirection:"column",backdropFilter:"blur(8px)",userSelect:"none" }}>
      <div className="lightbox-topbar" style={{ display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0.7rem clamp(0.8rem,2vw,1.4rem)",borderBottom:"1px solid #1E1E1E",background:"#0A0A0A",flexShrink:0,gap:"0.8rem" }}>
        <div>
          <div style={{ fontFamily:"'DM Mono',monospace",fontSize:"0.58rem",letterSpacing:"0.25em",color:CRIMSON,textTransform:"uppercase" }}>{item.cat}</div>
          <div style={{ fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:"0.82rem" }}>{item.name}{imgs.length>1&&<span style={{ fontFamily:"'DM Mono',monospace",fontSize:"0.62rem",color:"#5A5A5A",marginLeft:"0.8rem" }}>{slide+1}/{imgs.length}</span>}</div>
        </div>
        <div className="lightbox-controls" style={{ display:"flex",alignItems:"center",gap:"0.5rem" }}>
          {[{l:"−",a:()=>setZoom(z=>Math.max(1,+(z-0.5).toFixed(1)))},{l:"⊕",a:resetZoom},{l:"+",a:()=>setZoom(z=>Math.min(5,+(z+0.5).toFixed(1)))}].map(btn=>(
            <button key={btn.l} onClick={e=>{e.stopPropagation();btn.a();}} style={{ background:"transparent",border:"1px solid #1E1E1E",color:"#F0ECE8",fontFamily:"'DM Mono',monospace",fontSize:"0.8rem",width:"30px",height:"30px",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.2s" }}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=CRIMSON;e.currentTarget.style.color=CRIMSON;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor="#1E1E1E";e.currentTarget.style.color="#F0ECE8";}}>{btn.l}</button>
          ))}
          <button onClick={onClose} style={{ background:"transparent",border:"1px solid #1E1E1E",color:"#5A5A5A",fontFamily:"'DM Mono',monospace",fontSize:"0.6rem",letterSpacing:"0.15em",padding:"0.35rem 0.8rem",textTransform:"uppercase",transition:"all 0.2s",marginLeft:"0.3rem" }}
            onMouseEnter={e=>{e.currentTarget.style.borderColor=CRIMSON;e.currentTarget.style.color=CRIMSON;}}
            onMouseLeave={e=>{e.currentTarget.style.borderColor="#1E1E1E";e.currentTarget.style.color="#5A5A5A";}}>Fechar</button>
        </div>
      </div>
      <div onClick={e=>e.stopPropagation()} onWheel={onWheel} onMouseDown={onMouseDown} onMouseMove={onMouseMove} onMouseUp={onMouseUp} onMouseLeave={onMouseUp} onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}
        style={{ flex:1,overflow:"hidden",position:"relative",display:"flex",alignItems:"center",justifyContent:"center",cursor:zoom>1?(dragging?"grabbing":"grab"):"zoom-in" }}>
        <img src={src} alt={item.name} draggable={false} style={{ maxWidth:"100%",maxHeight:"100%",display:"block",transform:`scale(${zoom}) translate(${pos.x/zoom}px,${pos.y/zoom}px)`,transition:dragging?"none":"transform 0.2s ease",transformOrigin:"center center" }} />
        {hasPrev&&<button onClick={goPrev} style={{ position:"absolute",left:"0.8rem",top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,0.75)",border:`1px solid ${CRIMSON}`,color:"#fff",width:"40px",height:"40px",fontSize:"1.4rem",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10 }} onMouseEnter={e=>e.currentTarget.style.background=CRIMSON} onMouseLeave={e=>e.currentTarget.style.background="rgba(0,0,0,0.75)"}>‹</button>}
        {hasNext&&<button onClick={goNext} style={{ position:"absolute",right:"0.8rem",top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,0.75)",border:`1px solid ${CRIMSON}`,color:"#fff",width:"40px",height:"40px",fontSize:"1.4rem",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10 }} onMouseEnter={e=>e.currentTarget.style.background=CRIMSON} onMouseLeave={e=>e.currentTarget.style.background="rgba(0,0,0,0.75)"}>›</button>}
        {imgs.length>1&&<div style={{ position:"absolute",bottom:"1rem",left:0,right:0,display:"flex",justifyContent:"center",gap:"6px",zIndex:10 }}>
          {imgs.map((_,di)=><div key={di} onClick={()=>{setSlide(di);resetZoom();}} style={{ width:di===slide?"20px":"7px",height:"7px",borderRadius:"4px",background:di===slide?CRIMSON:"rgba(255,255,255,0.3)",transition:"all 0.25s",cursor:"pointer" }} />)}
        </div>}
      </div>
      {zoom===1&&<div style={{ textAlign:"center",padding:"0.5rem",fontFamily:"'DM Mono',monospace",fontSize:"0.58rem",letterSpacing:"0.2em",color:"#2a2a2a",flexShrink:0 }}>
        {imgs.length>1?"← → NAVEGAR · ":""}SCROLL · PINCH · +/− ZOOM · CLIQUE FORA PARA FECHAR
      </div>}
    </div>
  );
}

// ── PORTFOLIO CARD ────────────────────────────────────────────────────────────
function PortfolioCard({ item, i, hovered, setHovered, onOpen }) {
  const [slide, setSlide] = useState(0);
  const imgs = item.imgs || (item.img ? [item.img] : null);
  const hasImages = !!imgs;
  const isMulti = imgs && imgs.length > 1;
  const hasLink = !!item.link;
  const prev = (e) => { e.stopPropagation(); setSlide(s=>(s-1+imgs.length)%imgs.length); };
  const next = (e) => { e.stopPropagation(); setSlide(s=>(s+1)%imgs.length); };
  const src = imgs ? (imgs[slide].startsWith("http") ? imgs[slide] : `data:image/png;base64,${imgs[slide]}`) : "";

  const handleClick = () => {
    if (item.empty) return;
    if (hasLink) { window.open(item.link, "_blank", "noopener,noreferrer"); return; }
    if (hasImages) onOpen({ ...item, imgs });
  };

  const isClickable = !item.empty && (hasLink || hasImages);
  const linkIcon = hasLink ? "🔗" : "🔍";

  return (
    <div onMouseEnter={()=>setHovered(i)} onMouseLeave={()=>setHovered(null)} onClick={handleClick}
      style={{ position:"relative",aspectRatio:"4/3",overflow:"hidden",cursor:isClickable?"pointer":"default",background:item.empty?"rgba(199,37,26,0.04)":"#141414",border:item.empty?"1px dashed rgba(199,37,26,0.3)":"none" }}>
      {hasImages
        ?<div style={{ position:"absolute",inset:0,backgroundImage:`url('${src}')`,backgroundSize:"cover",backgroundPosition:"center",transition:"transform 0.4s ease",transform:hovered===i?"scale(1.05)":"scale(1)" }}/>
        :<div style={{ position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"2.2rem",color:item.empty?"rgba(199,37,26,0.3)":"#1E1E1E",transition:"transform 0.35s",transform:hovered===i?"scale(1.08)":"scale(1)" }}>{item.icon}</div>
      }
      {isMulti&&hovered===i&&(
        <>
          <button onClick={prev} style={{ position:"absolute",left:"0.4rem",top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,0.7)",border:`1px solid ${CRIMSON}`,color:"#fff",width:"26px",height:"26px",fontSize:"0.8rem",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10 }}>‹</button>
          <button onClick={next} style={{ position:"absolute",right:"0.4rem",top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,0.7)",border:`1px solid ${CRIMSON}`,color:"#fff",width:"26px",height:"26px",fontSize:"0.8rem",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10 }}>›</button>
        </>
      )}
      {isMulti&&<div style={{ position:"absolute",top:"0.6rem",left:"0.6rem",background:"rgba(0,0,0,0.75)",border:`1px solid ${CRIMSON}`,fontFamily:"'DM Mono',monospace",fontSize:"0.52rem",letterSpacing:"0.15em",color:CRIMSON,padding:"0.15rem 0.45rem",zIndex:10 }}>{slide+1}/{imgs.length}</div>}
      {isClickable&&<div style={{ position:"absolute",top:"0.6rem",right:"0.6rem",background:"rgba(0,0,0,0.7)",border:`1px solid ${CRIMSON}`,width:"26px",height:"26px",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"0.7rem",zIndex:10,opacity:hovered===i?1:0,transition:"opacity 0.25s,transform 0.25s",transform:hovered===i?"scale(1)":"scale(0.7)" }}>{linkIcon}</div>}
      <div style={{ position:"absolute",inset:0,padding:"1.2rem",background:item.empty?"none":"linear-gradient(to top,rgba(0,0,0,0.92) 0%,transparent 60%)",display:"flex",flexDirection:"column",justifyContent:"flex-end",opacity:item.empty?1:hovered===i?1:0,transition:"opacity 0.3s",pointerEvents:"none" }}>
        <div style={{ fontFamily:"'DM Mono',monospace",fontSize:"0.58rem",letterSpacing:"0.25em",color:CRIMSON,textTransform:"uppercase",marginBottom:"0.25rem" }}>{item.cat}</div>
        <div style={{ fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:"0.82rem" }}>{item.name}</div>
      </div>
      <div style={{ position:"absolute",inset:0,border:`2px solid ${CRIMSON}`,opacity:hovered===i&&!item.empty?1:0,transition:"opacity 0.2s",pointerEvents:"none" }} />
    </div>
  );
}

